-- ====================================================
-- SRC (수원러닝크루) 엑셀 데이터 마이그레이션 SQL 스크립트 (압축/최적화 버전)
-- ====================================================

-- 0. 기존 복사 데이터 병합 함수 정의 (RLS 우회 목적)
CREATE OR REPLACE FUNCTION public.merge_preseeded_profile(new_user_id UUID, user_nickname TEXT)
RETURNS BOOLEAN AS $$
DECLARE
    pre_seeded_id UUID;
    pre_seeded_role public.user_role;
    pre_seeded_exempted BOOLEAN;
    pre_seeded_active BOOLEAN;
BEGIN
    SELECT id, role, is_exempted, is_active 
    INTO pre_seeded_id, pre_seeded_role, pre_seeded_exempted, pre_seeded_active
    FROM public.profiles
    WHERE nickname = user_nickname AND id <> new_user_id
    LIMIT 1;

    IF pre_seeded_id IS NOT NULL THEN
        UPDATE public.running_records
        SET user_id = new_user_id
        WHERE user_id = pre_seeded_id;

        UPDATE public.marathon_pbs
        SET user_id = new_user_id
        WHERE user_id = pre_seeded_id;

        UPDATE public.profiles
        SET 
            role = pre_seeded_role,
            is_exempted = pre_seeded_exempted,
            is_active = pre_seeded_active,
            is_onboarded = true
        WHERE id = new_user_id;

        DELETE FROM public.profiles
        WHERE id = pre_seeded_id;

        DELETE FROM auth.users
        WHERE id = pre_seeded_id;

        RETURN TRUE;
    END IF;

    RETURN FALSE;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

BEGIN;
BEGIN;
ALTER TABLE public.profiles DISABLE TRIGGER ALL;

-- locations



























-- users





















































































































































































































































































-- profiles





















































































































































































































































































-- PBs




























































































































































































































ALTER TABLE public.profiles ENABLE TRIGGER ALL;
COMMIT;
